const cq = $input.first().json.callback_query;
const [idStr, action] = (cq.data || '').split(':');
const categoryMap = {
  'an_uong':  { en: 'Dining',        vi: '🍜 Ăn uống' },
  'tieu_vat': { en: 'Shopping',      vi: '🛍 Tiêu vặt' },
  'vay':      { en: 'Transfer',      vi: '💸 Vay' },
  'nha_cua':  { en: 'Utilities',     vi: '🏠 Nhà cửa' },
  'luong':    { en: 'Salary',        vi: '💼 Lương' },
  'dau_tu':   { en: 'Investment',    vi: '📈 Đầu tư' },
  'tra_no':   { en: 'Debt_Repaid',   vi: '🤝 Được trả nợ' },
  'thuong':   { en: 'Bonus',         vi: '🎁 Thưởng' },
  'thu_khac': { en: 'Other_Income',  vi: '💰 Thu khác' },
};
const merchantMap = {
  'merchant_hoang': 'HOANG NHAT HOANG',
  'merchant_dung':  'LE THI THANH DUNG',
};
const cat = categoryMap[action];
const merchantName = merchantMap[action] || null;
return [{ json: {
  receipt_id:        parseInt(idStr),
  action:            action,
  is_edit:           action === 'edit',
  is_category:       !!cat,
  is_merchant_select: !!merchantName,
  merchant_name:     merchantName,
  category_en:       cat ? cat.en : null,
  category_vi:       cat ? cat.vi : null,
  cq_id:             cq.id,
  chat_id:           cq.message.chat.id,
  message_id:        cq.message.message_id,
}}];

const cb = $('Parse Callback').first().json;
const r = $('Set Merchant').first().json;
const amt = Number(r.total_amount).toLocaleString('vi-VN');
const timeVal = r.transaction_time ? String(r.transaction_time).slice(0,5) + ' ' : '';
const [y,m,d] = String(r.date).split('T')[0].split('-');
const dateDisplay = timeVal + d+'/'+m+'/'+y;
const isIncome = r.transaction_type === 'income';
const typeIcon = isIncome ? '💚 Thu nhập' : '🔴 Chi tiêu';
const text = '📋 *Đã đọc hoá đơn:*\n🏪 ' + r.merchant + '\n💰 ' + amt + ' ' + r.currency + '\n📅 ' + dateDisplay + '\n' + typeIcon + '\n\nChọn danh mục:';
const sid = String(r.id);
const editUrl = sid+':edit';
const keyboard = isIncome ? [
  [{text: '💼 Lương', callback_data: sid+':luong'}, {text: '📈 Đầu tư', callback_data: sid+':dau_tu'}],
  [{text: '🤝 Được trả nợ', callback_data: sid+':tra_no'}, {text: '🎁 Thưởng', callback_data: sid+':thuong'}],
  [{text: '💰 Thu khác', callback_data: sid+':thu_khac'}],
  [{text: '✏️ Chỉnh sửa', callback_data: editUrl}]
] : [
  [{text: '🍜 Ăn uống', callback_data: sid+':an_uong'}, {text: '🛍 Tiêu vặt', callback_data: sid+':tieu_vat'}],
  [{text: '💸 Vay', callback_data: sid+':vay'}, {text: '🏠 Nhà cửa', callback_data: sid+':nha_cua'}],
  [{text: '✏️ Chỉnh sửa', callback_data: editUrl}]
];
return [{ json: { chat_id: cb.chat_id, message_id: cb.message_id, text: text, keyboard: keyboard } }];

const cb = $('Parse Callback').first().json;
const dr = $('Get Draft Fields').first().json;
const timeVal = dr.transaction_time ? String(dr.transaction_time).slice(0,5) : '';
const [y,m,d] = String(dr.date).split('T')[0].split('-');
const dateDisplay = d + '/' + m + '/' + y;
const merchantVal = dr.merchant || '';
const text = '✏️ Chỉnh sửa thông tin (reply để cập nhật):\n\nmerchant: ' + merchantVal + '\namount: ' + dr.total_amount + '\ncurrency: ' + dr.currency + '\ndate: ' + dateDisplay + '\ntime: ' + timeVal;
return [{ json: { chat_id: cb.chat_id, text: text } }];

const cb = $('Parse Callback').first().json;
const r = $('Save Category').first().json;
const timeVal = r.transaction_time ? String(r.transaction_time).slice(0,5) + ' ' : '';
const [y,m,d] = String(r.date).split('T')[0].split('-');
const dateStr = timeVal + d + '/' + m + '/' + y;
const text = '📋 *Hoá đơn:*\n🏪 ' + r.merchant + '\n💰 ' + r.total_amount + ' ' + r.currency + '\n📅 ' + dateStr + '\n' + r.category_vi + ' ✓';
return [{ json: { chat_id: cb.chat_id, message_id: cb.message_id, text: text } }];

const msg = $input.first().json.message;
const photos = msg.photo;
const nameMap = { 661762284: 'HOANG NHAT HOANG', 1915103492: 'LE THI THANH DUNG' };
const sender_id = msg.from.id;
const sender_name = nameMap[sender_id] || (msg.from.first_name + (msg.from.last_name ? ' ' + msg.from.last_name : '')).toUpperCase();
return [{ json: { file_id: photos[photos.length-1].file_id, chat_id: msg.chat.id, sender_id: sender_id, sender_name: sender_name } }];

const body = $input.first().json;
const src = $('Extract File ID').first().json;
const chatId = src.chat_id;
if (body.error) return [{ json: { valid: false, reason: 'Không thể đọc ảnh.', chat_id: chatId } }];
const d = body.data || {};
const missing = [];
if (d.total_amount == null) missing.push('số tiền');
if (!d.currency) missing.push('đơn vị tiền');
if (!d.date) missing.push('ngày');
if (missing.length > 0) return [{ json: { valid: false, reason: 'Không tìm thấy: ' + missing.join(', '), chat_id: chatId } }];
const [y,m,day] = d.date.split('-');
return [{ json: {
  valid: true,
  merchant:     d.merchant ? String(d.merchant).slice(0,255) : null,
  total_amount: Number(d.total_amount),
  currency:     String(d.currency).toUpperCase().slice(0,3),
  date:         d.date,
  time:         d.time || null,
  date_display: (d.time ? d.time + ' ' : '') + day + '/' + m + '/' + y,
  description:  d.description ? String(d.description).slice(0,500) : null,
  ocr_text:     String(body.ocr_text||'').slice(0,2000),
  chat_id:          chatId,
  sender_id:        src.sender_id,
  sender_name:      src.sender_name,
  transaction_type: d.transaction_type === 'income' ? 'income' : 'expense',
}}];
const out = result[0].json;
out.owner_name = out.transaction_type === 'income' ? (out.merchant || null) : out.sender_name;
return result;

const v = $('Validate & Format').first().json;
const id = $('Save Draft').first().json.id;
const amt = Number(v.total_amount).toLocaleString('vi-VN');
const descPart = v.description ? '\n📄 ' + v.description : '';
const isIncome = v.transaction_type === 'income';
const typeIcon = isIncome ? '💚 Thu nhập' : '🔴 Chi tiêu';
const merchantLine = v.merchant ? '🏪 ' + v.merchant : '🏪 ❓ Chưa rõ — chọn bên dưới hoặc nhấn ✏️';
const text = '📋 *Đã đọc hoá đơn:*\n' + merchantLine + '\n💰 ' + amt + ' ' + v.currency + '\n📅 ' + v.date_display + '\n' + typeIcon + descPart + '\n\nChọn danh mục:';
const sid = String(id);
const merchantRow = !v.merchant ? [[{text: '👤 Hoàng (Anh)', callback_data: sid+':merchant_hoang'}, {text: '👤 Dung (Vợ)', callback_data: sid+':merchant_dung'}]] : [];
const keyboard = [...merchantRow, ...(isIncome ? [
  [{text: '💼 Lương', callback_data: sid+':luong'}, {text: '📈 Đầu tư', callback_data: sid+':dau_tu'}],
  [{text: '🤝 Được trả nợ', callback_data: sid+':tra_no'}, {text: '🎁 Thưởng', callback_data: sid+':thuong'}],
  [{text: '💰 Thu khác', callback_data: sid+':thu_khac'}],
  [{text: '✏️ Chỉnh sửa', callback_data: sid+':edit'}]
] : [
  [{text: '🍜 Ăn uống', callback_data: sid+':an_uong'}, {text: '🛍 Tiêu vặt', callback_data: sid+':tieu_vat'}],
  [{text: '💸 Vay', callback_data: sid+':vay'}, {text: '🏠 Nhà cửa', callback_data: sid+':nha_cua'}],
  [{text: '✏️ Chỉnh sửa', callback_data: sid+':edit'}]
])];
return [{ json: { chat_id: v.chat_id, receipt_id: id, text: text, keyboard: keyboard } }];

