const text = $('Telegram Trigger').first().json.message.text || '';
const chatId = $('Telegram Trigger').first().json.message.chat.id;
const draft = $('Get Pending Receipt').first().json;

const fields = {};
for (const line of text.split('\n')) {
  const idx = line.indexOf(':');
  if (idx === -1) continue;
  const key = line.slice(0, idx).trim().toLowerCase();
  const val = line.slice(idx+1).trim();
  if (val) fields[key] = val;
}

let date = String(draft.date).split('T')[0];
if (fields.date && fields.date.includes('/')) {
  const [d,m,y] = fields.date.split('/');
  date = y + '-' + m.padStart(2,'0') + '-' + d.padStart(2,'0');
}

let time = draft.transaction_time ? String(draft.transaction_time).slice(0,5) : null;
if (fields.time) time = fields.time.slice(0,5);

const [yr,mo,dy] = date.split('-');
return [{ json: {
  draft_id:     draft.id,
  chat_id:      chatId,
  merchant:     String(fields.merchant || draft.merchant).slice(0,255),
  total_amount: Number(fields.amount || draft.total_amount),
  currency:     String(fields.currency || draft.currency).toUpperCase().slice(0,3),
  date:         date,
  time:         time,
  date_display: (time ? time + ' ' : '') + dy + '/' + mo + '/' + yr,
  transaction_type: draft.transaction_type || 'expense',
}}];

const v = $('Parse Edit Fields').first().json;
const id = $('Update Draft').first().json.id;
const amt = Number(v.total_amount).toLocaleString('vi-VN');
const merchantLine = v.merchant ? '🏪 ' + v.merchant : '🏪 ❓ Chưa rõ — nhấn ✏️ để chỉnh sửa';
const text = '✅ *Đã cập nhật! Chọn danh mục:*\n' + merchantLine + '\n💰 ' + amt + ' ' + v.currency + '\n📅 ' + v.date_display;
const isIncome = v.transaction_type === 'income';
const sid = String(id);
const keyboard = isIncome ? [
  [{text: '💼 Lương', callback_data: sid+':luong'}, {text: '📈 Đầu tư', callback_data: sid+':dau_tu'}],
  [{text: '🤝 Được trả nợ', callback_data: sid+':tra_no'}, {text: '🎁 Thưởng', callback_data: sid+':thuong'}],
  [{text: '💰 Thu khác', callback_data: sid+':thu_khac'}],
  [{text: '✏️ Chỉnh sửa', callback_data: sid+':edit'}]
] : [
  [{text: '🍜 Ăn uống', callback_data: sid+':an_uong'}, {text: '🛍 Tiêu vặt', callback_data: sid+':tieu_vat'}],
  [{text: '💸 Vay', callback_data: sid+':vay'}, {text: '🏠 Nhà cửa', callback_data: sid+':nha_cua'}],
  [{text: '✏️ Chỉnh sửa', callback_data: sid+':edit'}]
];
return [{ json: { chat_id: v.chat_id, receipt_id: id, text: text, keyboard: keyboard } }];

const msg = $input.first().json.message;
const raw = msg.web_app_data.data;
const d = JSON.parse(raw);
const chatId = msg.chat.id;

let date = null;
if (d.date) {
  if (d.date.includes('/')) {
    const parts = d.date.split(' ');
    const datePart = parts[parts.length - 1];
    const [dd, mm, yyyy] = datePart.split('/');
    date = yyyy + '-' + mm.padStart(2,'0') + '-' + dd.padStart(2,'0');
  } else {
    date = d.date;
  }
}

const time = d.time ? String(d.time).slice(0,5) : null;
const [y,m,dy] = (date||'').split('-');
const dateDisplay = date ? (time ? time+' ' : '') + dy+'/'+m+'/'+y : '';

return [{ json: {
  draft_id:     d.receipt_id,
  chat_id:      chatId,
  merchant:     d.merchant ? String(d.merchant).slice(0,255) : null,
  total_amount: Number(d.amount),
  currency:     String(d.currency||'VND').toUpperCase().slice(0,3),
  date:         date,
  time:         time,
  date_display: dateDisplay,
  transaction_type: 'expense',
}}];

const parsed = $('Parse Web App Data').first().json;
const typeRow = $('Get Receipt Type').first().json;
return [{ json: { ...parsed, transaction_type: typeRow.transaction_type || 'expense' } }];

const rows = $input.all().map(r => r.json);
const chatId = $('Telegram Trigger').first().json.message.chat.id;
if (rows.length === 0) {
  return [{ json: { chat_id: chatId, text: '📊 Chưa có giao dịch nào được lưu.' } }];
}
// Group by month
const byMonth = {};
for (const row of rows) {
  const m = row.month;
  if (!byMonth[m]) byMonth[m] = [];
  byMonth[m].push(row);
}
let text = '📊 *Tổng chi tiêu theo tháng:*';
for (const [month, items] of Object.entries(byMonth)) {
  const monthTotal = items.reduce((s, r) => s + Number(r.total), 0);
  text += '\n\n📅 *' + month + '*';
  for (const item of items) {
    const cat = item.category_vi || '❓ Khác';
    const amt = Number(item.total).toLocaleString('vi-VN');
    text += '\n  ' + cat + ': ' + amt + ' ' + item.currency;
  }
  text += '\n  ─────────────';
  text += '\n  Tổng: ' + monthTotal.toLocaleString('vi-VN') + ' VND';
}
return [{ json: { chat_id: chatId, text: text } }];
